+
+/**
+ * Draws a 1px dark outline around a character sprite for better visibility.
+ * Outline is drawn around all non-transparent pixels without affecting sprite colors.
+ */
+export function drawCharacterOutline(
+  ctx: CanvasRenderingContext2D,
+  sprite: string[],
+  palette: Record<string, string>,
+  x: number,
+  y: number,
+  s: number,
+  flipH: boolean,
+) {
+  // Draw outline by checking each pixel and drawing a 1px black rectangle around non-transparent pixels
+  const outlineColor = '#000000';
+  for (let row = 0; row < sprite.length; row++) {
+    const line = sprite[row];
+    for (let col = 0; col < line.length; col++) {
+      const c = line[col];
+      if (c === ' ') continue;
+      const drawX = flipH ? x + (line.length - 1 - col) * s : x + col * s;
+      const drawY = y + row * s;
+      // Draw outline pixels around current pixel if adjacent pixel is transparent or out of bounds
+      const neighbors = [
+        [col - 1, row], [col + 1, row], [col, row - 1], [col, row + 1],
+      ];
+      for (const [nx, ny] of neighbors) {
+        if (ny < 0 || ny >= sprite.length || nx < 0 || nx >= line.length || sprite[ny][nx] === ' ') {
+          const ox = flipH ? x + (line.length - 1 - nx) * s : x + nx * s;
+          const oy = y + ny * s;
+          ctx.fillStyle = outlineColor;
+          ctx.fillRect(ox, oy, s, s);
+        }
+      }
+    }
+  }
+}
+
+/**
+ * Draws an elliptical shadow beneath the character sprite.
+ */
+export function drawCharacterShadow(
+  ctx: CanvasRenderingContext2D,
+  x: number,
+  y: number,
+  spriteHeight: number,
+  s: number,
+) {
+  ctx.fillStyle = 'rgba(0,0,0,0.25)';
+  ctx.beginPath();
+  ctx.ellipse(x + 8 * s, y + spriteHeight * s + 4, 8 * s, 3 * s, 0, 0, Math.PI * 2);
+  ctx.fill();
 }
